node -e "
const c = require('./.forge/config.json');
const required = [
  ['version', c.version],
  ['project.name', c.project?.name],
  ['project.prefix', c.project?.prefix],
  ['stack', c.stack],
  ['commands', c.commands],
  ['paths.engineering', c.paths?.engineering],
  ['paths.store', c.paths?.store],
  ['paths.workflows', c.paths?.workflows],
];
let ok = true;
for (const [k, v] of required) {
  const present = v !== undefined && v !== null && v !== '';
  console.log(k + ': ' + (present ? '✓' : '✗ MISSING') + ' → ' + JSON.stringify(v));
  if (!present) ok = false;
}
console.log(ok ? '\nAll 8 required keys present ✓' : '\nSome keys missing ✗');
"

node -e "
// Matching skills for this project's stack
// Stack: Rust (primary), MCP server code
// Already installed (from list-skills.js output):
const installed = [
  'agent-sdk-dev', 'clangd-lsp', 'frontend-design', 'huggingface-best',
  'pyright-lsp', 'skill-creator', 'streetview-panorama-js',
  'stripe-integration', 'typescript-lsp', 'vue-best-practices'
];

// Recommended for this stack:
const recommendations = {
  'rust-analyzer-lsp': { confidence: 'High', reason: 'Rust is the primary language', installed: false },
  'mcp-server-dev':    { confidence: 'High', reason: 'Project IS an MCP server (grove serve)', installed: false },
  'security-guidance': { confidence: 'Medium', reason: 'Relevant for any project', installed: false },
  'agent-sdk-dev':     { confidence: 'High', reason: 'MCP/agent SDK patterns', installed: true },
};

console.log('=== Skill Recommendations for Grove ===');
console.log();
for (const [skill, info] of Object.entries(recommendations)) {
  console.log(\`[\${info.confidence}] \${skill} — \${info.reason} (\${info.installed ? 'ALREADY INSTALLED' : 'NOT INSTALLED'})\`);
}
console.log();
console.log('Already installed but NOT matching this stack:');
installed.filter(s => !Object.keys(recommendations).includes(s)).forEach(s => console.log('  ' + s));
"
